Sub 'PrintFilters'
/* Generated by DVelop Work With Plus Pattern [Start] - Do not change */
If not &PesIntVenCod.IsEmpty() print printBlockFilterPesIntVenCod EndIf If not &PesIntBlo.IsEmpty() &FilterPesIntBloValueDescription = '' Do Case Case &PesIntBlo.ToString().Trim() = !"0" &FilterPesIntBloValueDescription = "Somente Meus Clientes"
Case &PesIntBlo.ToString().Trim() = !"1" &FilterPesIntBloValueDescription = " Clientes Liberados para Venda"
Case &PesIntBlo.ToString().Trim() = !"2" &FilterPesIntBloValueDescription = " Somente Clientes no 1"
EndCase
print printBlockFilterPesIntBlo EndIf If not &PesCod.IsEmpty() print printBlockFilterPesCod EndIf If not &PesCidAreCod.IsEmpty() print printBlockFilterPesCidAreCod EndIf If not &PesPrxLigDta.IsEmpty() print printBlockFilterPesPrxLigDta EndIf If not &PesPrxLigDta_To.IsEmpty() &PesPrxLigDta_To_Description = format('%1 (%2)', "Agenda", "até") print printBlockFilterPesPrxLigDta_To EndIf If not &TodosAgendados.IsEmpty() print printBlockFilterTodosAgendados EndIf If not &PesSts.IsEmpty() &FilterPesStsValueDescription = &PesSts.EnumerationDescription()
print printBlockFilterPesSts EndIf If not &PesIsCli.IsEmpty() print printBlockFilterPesIsCli EndIf If not &PesIsCli_To.IsEmpty() &PesIsCli_To_Description = format('%1 (%2)', "Pessoa Cliente", " - ") print printBlockFilterPesIsCli_To EndIf If not &PesCliHabVenInt.IsEmpty() print printBlockFilterPesCliHabVenInt EndIf If &GridState.DynamicFilters.Count >= 1 &GridStateDynamicFilter = &GridState.DynamicFilters.Item(1) &DynamicFiltersSelector1 = &GridStateDynamicFilter.Selected Do Case Case &DynamicFiltersSelector1 = !'PESRAZ' &PesRaz1.FromString(&GridStateDynamicFilter.Value) If not &PesRaz1.IsEmpty() &PesRaz = &PesRaz1 print printBlockFilterPesRaz EndIf Case &DynamicFiltersSelector1 = !'PESCIDUFECOD' &PesCidUfeCod1.FromString(&GridStateDynamicFilter.Value) If not &PesCidUfeCod1.IsEmpty() &PesCidUfeCod = &PesCidUfeCod1 print printBlockFilterPesCidUfeCod EndIf Case &DynamicFiltersSelector1 = !'PESCIDCOD' &PesCidCod1.FromString(&GridStateDynamicFilter.Value) If not &PesCidCod1.IsEmpty() &PesCidCod = &PesCidCod1 print printBlockFilterPesCidCod EndIf Case &DynamicFiltersSelector1 = !'PESCIDNOM' &PesCidNom1.FromString(&GridStateDynamicFilter.Value) If not &PesCidNom1.IsEmpty() &PesCidNom = &PesCidNom1 print printBlockFilterPesCidNom EndIf Case &DynamicFiltersSelector1 = !'RATCOD' &RatCod1.FromString(&GridStateDynamicFilter.Value) If not &RatCod1.IsEmpty() &RatCod = &RatCod1 print printBlockFilterRatCod EndIf Case &DynamicFiltersSelector1 = !'PESCPF' &PesCpf1.FromString(&GridStateDynamicFilter.Value) If not &PesCpf1.IsEmpty() &PesCpf = &PesCpf1 print printBlockFilterPesCpf EndIf Case &DynamicFiltersSelector1 = !'PESULTVENDTA' &PesUltVenDta1.FromString(&GridStateDynamicFilter.Value) &PesUltVenDta_To1.FromString(&GridStateDynamicFilter.ValueTo) If not &PesUltVenDta1.IsEmpty() &FilterPesUltVenDtaDescription = "Última Compra" &PesUltVenDta = &PesUltVenDta1 print printBlockFilterPesUltVenDta EndIf If not &PesUltVenDta_To1.IsEmpty() &FilterPesUltVenDtaDescription = format('%1 (%2)', "Última Compra", "até") &PesUltVenDta = &PesUltVenDta_To1 print printBlockFilterPesUltVenDta EndIf EndCase If &GridState.DynamicFilters.Count >= 2 &DynamicFiltersEnabled2 = True &GridStateDynamicFilter = &GridState.DynamicFilters.Item(2) &DynamicFiltersSelector2 = &GridStateDynamicFilter.Selected Do Case Case &DynamicFiltersSelector2 = !'PESRAZ' &PesRaz2.FromString(&GridStateDynamicFilter.Value) If not &PesRaz2.IsEmpty() &PesRaz = &PesRaz2 print printBlockFilterPesRaz EndIf Case &DynamicFiltersSelector2 = !'PESCIDUFECOD' &PesCidUfeCod2.FromString(&GridStateDynamicFilter.Value) If not &PesCidUfeCod2.IsEmpty() &PesCidUfeCod = &PesCidUfeCod2 print printBlockFilterPesCidUfeCod EndIf Case &DynamicFiltersSelector2 = !'PESCIDCOD' &PesCidCod2.FromString(&GridStateDynamicFilter.Value) If not &PesCidCod2.IsEmpty() &PesCidCod = &PesCidCod2 print printBlockFilterPesCidCod EndIf Case &DynamicFiltersSelector2 = !'PESCIDNOM' &PesCidNom2.FromString(&GridStateDynamicFilter.Value) If not &PesCidNom2.IsEmpty() &PesCidNom = &PesCidNom2 print printBlockFilterPesCidNom EndIf Case &DynamicFiltersSelector2 = !'RATCOD' &RatCod2.FromString(&GridStateDynamicFilter.Value) If not &RatCod2.IsEmpty() &RatCod = &RatCod2 print printBlockFilterRatCod EndIf Case &DynamicFiltersSelector2 = !'PESCPF' &PesCpf2.FromString(&GridStateDynamicFilter.Value) If not &PesCpf2.IsEmpty() &PesCpf = &PesCpf2 print printBlockFilterPesCpf EndIf Case &DynamicFiltersSelector2 = !'PESULTVENDTA' &PesUltVenDta2.FromString(&GridStateDynamicFilter.Value) &PesUltVenDta_To2.FromString(&GridStateDynamicFilter.ValueTo) If not &PesUltVenDta2.IsEmpty() &FilterPesUltVenDtaDescription = "Última Compra" &PesUltVenDta = &PesUltVenDta2 print printBlockFilterPesUltVenDta EndIf If not &PesUltVenDta_To2.IsEmpty() &FilterPesUltVenDtaDescription = format('%1 (%2)', "Última Compra", "até") &PesUltVenDta = &PesUltVenDta_To2 print printBlockFilterPesUltVenDta EndIf EndCase If &GridState.DynamicFilters.Count >= 3 &DynamicFiltersEnabled3 = True &GridStateDynamicFilter = &GridState.DynamicFilters.Item(3) &DynamicFiltersSelector3 = &GridStateDynamicFilter.Selected Do Case Case &DynamicFiltersSelector3 = !'PESRAZ' &PesRaz3.FromString(&GridStateDynamicFilter.Value) If not &PesRaz3.IsEmpty() &PesRaz = &PesRaz3 print printBlockFilterPesRaz EndIf Case &DynamicFiltersSelector3 = !'PESCIDUFECOD' &PesCidUfeCod3.FromString(&GridStateDynamicFilter.Value) If not &PesCidUfeCod3.IsEmpty() &PesCidUfeCod = &PesCidUfeCod3 print printBlockFilterPesCidUfeCod EndIf Case &DynamicFiltersSelector3 = !'PESCIDCOD' &PesCidCod3.FromString(&GridStateDynamicFilter.Value) If not &PesCidCod3.IsEmpty() &PesCidCod = &PesCidCod3 print printBlockFilterPesCidCod EndIf Case &DynamicFiltersSelector3 = !'PESCIDNOM' &PesCidNom3.FromString(&GridStateDynamicFilter.Value) If not &PesCidNom3.IsEmpty() &PesCidNom = &PesCidNom3 print printBlockFilterPesCidNom EndIf Case &DynamicFiltersSelector3 = !'RATCOD' &RatCod3.FromString(&GridStateDynamicFilter.Value) If not &RatCod3.IsEmpty() &RatCod = &RatCod3 print printBlockFilterRatCod EndIf Case &DynamicFiltersSelector3 = !'PESCPF' &PesCpf3.FromString(&GridStateDynamicFilter.Value) If not &PesCpf3.IsEmpty() &PesCpf = &PesCpf3 print printBlockFilterPesCpf EndIf Case &DynamicFiltersSelector3 = !'PESULTVENDTA' &PesUltVenDta3.FromString(&GridStateDynamicFilter.Value) &PesUltVenDta_To3.FromString(&GridStateDynamicFilter.ValueTo) If not &PesUltVenDta3.IsEmpty() &FilterPesUltVenDtaDescription = "Última Compra" &PesUltVenDta = &PesUltVenDta3 print printBlockFilterPesUltVenDta EndIf If not &PesUltVenDta_To3.IsEmpty() &FilterPesUltVenDtaDescription = format('%1 (%2)', "Última Compra", "até") &PesUltVenDta = &PesUltVenDta_To3 print printBlockFilterPesUltVenDta EndIf EndCase If &GridState.DynamicFilters.Count >= 4 &DynamicFiltersEnabled4 = True &GridStateDynamicFilter = &GridState.DynamicFilters.Item(4) &DynamicFiltersSelector4 = &GridStateDynamicFilter.Selected Do Case Case &DynamicFiltersSelector4 = !'PESRAZ' &PesRaz4.FromString(&GridStateDynamicFilter.Value) If not &PesRaz4.IsEmpty() &PesRaz = &PesRaz4 print printBlockFilterPesRaz EndIf Case &DynamicFiltersSelector4 = !'PESCIDUFECOD' &PesCidUfeCod4.FromString(&GridStateDynamicFilter.Value) If not &PesCidUfeCod4.IsEmpty() &PesCidUfeCod = &PesCidUfeCod4 print printBlockFilterPesCidUfeCod EndIf Case &DynamicFiltersSelector4 = !'PESCIDCOD' &PesCidCod4.FromString(&GridStateDynamicFilter.Value) If not &PesCidCod4.IsEmpty() &PesCidCod = &PesCidCod4 print printBlockFilterPesCidCod EndIf Case &DynamicFiltersSelector4 = !'PESCIDNOM' &PesCidNom4.FromString(&GridStateDynamicFilter.Value) If not &PesCidNom4.IsEmpty() &PesCidNom = &PesCidNom4 print printBlockFilterPesCidNom EndIf Case &DynamicFiltersSelector4 = !'RATCOD' &RatCod4.FromString(&GridStateDynamicFilter.Value) If not &RatCod4.IsEmpty() &RatCod = &RatCod4 print printBlockFilterRatCod EndIf Case &DynamicFiltersSelector4 = !'PESCPF' &PesCpf4.FromString(&GridStateDynamicFilter.Value) If not &PesCpf4.IsEmpty() &PesCpf = &PesCpf4 print printBlockFilterPesCpf EndIf Case &DynamicFiltersSelector4 = !'PESULTVENDTA' &PesUltVenDta4.FromString(&GridStateDynamicFilter.Value) &PesUltVenDta_To4.FromString(&GridStateDynamicFilter.ValueTo) If not &PesUltVenDta4.IsEmpty() &FilterPesUltVenDtaDescription = "Última Compra" &PesUltVenDta = &PesUltVenDta4 print printBlockFilterPesUltVenDta EndIf If not &PesUltVenDta_To4.IsEmpty() &FilterPesUltVenDtaDescription = format('%1 (%2)', "Última Compra", "até") &PesUltVenDta = &PesUltVenDta_To4 print printBlockFilterPesUltVenDta EndIf EndCase If &GridState.DynamicFilters.Count >= 5 &DynamicFiltersEnabled5 = True &GridStateDynamicFilter = &GridState.DynamicFilters.Item(5) &DynamicFiltersSelector5 = &GridStateDynamicFilter.Selected Do Case Case &DynamicFiltersSelector5 = !'PESRAZ' &PesRaz5.FromString(&GridStateDynamicFilter.Value) If not &PesRaz5.IsEmpty() &PesRaz = &PesRaz5 print printBlockFilterPesRaz EndIf Case &DynamicFiltersSelector5 = !'PESCIDUFECOD' &PesCidUfeCod5.FromString(&GridStateDynamicFilter.Value) If not &PesCidUfeCod5.IsEmpty() &PesCidUfeCod = &PesCidUfeCod5 print printBlockFilterPesCidUfeCod EndIf Case &DynamicFiltersSelector5 = !'PESCIDCOD' &PesCidCod5.FromString(&GridStateDynamicFilter.Value) If not &PesCidCod5.IsEmpty() &PesCidCod = &PesCidCod5 print printBlockFilterPesCidCod EndIf Case &DynamicFiltersSelector5 = !'PESCIDNOM' &PesCidNom5.FromString(&GridStateDynamicFilter.Value) If not &PesCidNom5.IsEmpty() &PesCidNom = &PesCidNom5 print printBlockFilterPesCidNom EndIf Case &DynamicFiltersSelector5 = !'RATCOD' &RatCod5.FromString(&GridStateDynamicFilter.Value) If not &RatCod5.IsEmpty() &RatCod = &RatCod5 print printBlockFilterRatCod EndIf Case &DynamicFiltersSelector5 = !'PESCPF' &PesCpf5.FromString(&GridStateDynamicFilter.Value) If not &PesCpf5.IsEmpty() &PesCpf = &PesCpf5 print printBlockFilterPesCpf EndIf Case &DynamicFiltersSelector5 = !'PESULTVENDTA' &PesUltVenDta5.FromString(&GridStateDynamicFilter.Value) &PesUltVenDta_To5.FromString(&GridStateDynamicFilter.ValueTo) If not &PesUltVenDta5.IsEmpty() &FilterPesUltVenDtaDescription = "Última Compra" &PesUltVenDta = &PesUltVenDta5 print printBlockFilterPesUltVenDta EndIf If not &PesUltVenDta_To5.IsEmpty() &FilterPesUltVenDtaDescription = format('%1 (%2)', "Última Compra", "até") &PesUltVenDta = &PesUltVenDta_To5 print printBlockFilterPesUltVenDta EndIf EndCase EndIf EndIf EndIf EndIf EndIf
/* Generated by DVelop Work With Plus Pattern [End] - Do not change */
EndSub
Sub 'PrintColumnTitles'
/* Generated by DVelop Work With Plus Pattern [Start] - Do not change */
print printBlockBeforeGrid print printBlockLines_titles
/* Generated by DVelop Work With Plus Pattern [End] - Do not change */
EndSub
Sub 'PrintData'
/* Generated by DVelop Work With Plus Pattern [Start] - Do not change */
For each order EmpCod PesSts PesIsCli PesCliHabVenInt PesRaz when &OrderedBy = 1 order EmpCod PesSts PesIsCli PesCliHabVenInt PesCidUfeCod PesCidNom PesRaz when &OrderedBy = 2 order EmpCod PesSts PesIsCli PesCliHabVenInt PesPrxLig PesRaz when &OrderedBy = 3 order EmpCod PesSts PesIsCli PesCliHabVenInt (PesUltVenDta) PesRaz when &OrderedBy = 4
using DSwwClienteTelevendas(&PesIntVenCod, &PesIntBlo, &PesCod, &PesCidAreCod, &PesPrxLigDta, &PesPrxLigDta_To , &TodosAgendados, &PesSts, &PesIsCli, &PesIsCli_To, &PesCliHabVenInt, &DynamicFiltersSelector1 , &PesRaz1, &PesCidUfeCod1, &PesCidCod1, &PesCidNom1, &RatCod1, &PesCpf1 , &PesUltVenDta1, &PesUltVenDta_To1, &DynamicFiltersEnabled2, &DynamicFiltersSelector2, &PesRaz2, &PesCidUfeCod2 , &PesCidCod2, &PesCidNom2, &RatCod2, &PesCpf2, &PesUltVenDta2, &PesUltVenDta_To2 , &DynamicFiltersEnabled3, &DynamicFiltersSelector3, &PesRaz3, &PesCidUfeCod3, &PesCidCod3, &PesCidNom3 , &RatCod3, &PesCpf3, &PesUltVenDta3, &PesUltVenDta_To3, &DynamicFiltersEnabled4, &DynamicFiltersSelector4 , &PesRaz4, &PesCidUfeCod4, &PesCidCod4, &PesCidNom4, &RatCod4, &PesCpf4 , &PesUltVenDta4, &PesUltVenDta_To4, &DynamicFiltersEnabled5, &DynamicFiltersSelector5, &PesRaz5, &PesCidUfeCod5 , &PesCidCod5, &PesCidNom5, &RatCod5, &PesCpf5, &PesUltVenDta5, &PesUltVenDta_To5) If Not PesClaTip.IsEmpty() &PesClaTipDescription = PesClaTip.EnumerationDescription() Else &PesClaTipDescription.SetEmpty() Endif
Do 'BeforePrintLine' print printBlockLines_data Do 'AfterPrintLine' EndFor
/* Generated by DVelop Work With Plus Pattern [End] - Do not change */
EndSub
Sub 'LoadGridState'
/* Generated by DVelop Work With Plus Pattern [Start] - Do not change */
// Load grid state from session. If &Session.Get(!"wwClienteTelevendasGridState") = !"" &GridState.FromXml(LoadGridState.Udp(!"wwClienteTelevendasGridState")) Else &GridState.FromXml(&Session.Get(!"wwClienteTelevendasGridState")) Endif
&OrderedBy = &GridState.OrderedBy
For &GridStateFilterValue in &GridState.FilterValues Do Case Case &GridStateFilterValue.Name = !"PESINTVENCOD" &PesIntVenCod.FromString(&GridStateFilterValue.Value) Case &GridStateFilterValue.Name = !"PESINTBLO" &PesIntBlo.FromString(&GridStateFilterValue.Value) Case &GridStateFilterValue.Name = !"PESCOD" &PesCod.FromString(&GridStateFilterValue.Value) Case &GridStateFilterValue.Name = !"PESCIDARECOD" &PesCidAreCod.FromString(&GridStateFilterValue.Value) Case &GridStateFilterValue.Name = !"PESPRXLIGDTA" &PesPrxLigDta.FromString(&GridStateFilterValue.Value) &PesPrxLigDta_To.FromString(&GridStateFilterValue.ValueTo) Case &GridStateFilterValue.Name = !"TODOSAGENDADOS" &TodosAgendados.FromString(&GridStateFilterValue.Value) Case &GridStateFilterValue.Name = !"PESSTS" &PesSts.FromString(&GridStateFilterValue.Value) Case &GridStateFilterValue.Name = !"PESISCLI" &PesIsCli.FromString(&GridStateFilterValue.Value) &PesIsCli_To.FromString(&GridStateFilterValue.ValueTo) Case &GridStateFilterValue.Name = !"PESCLIHABVENINT" &PesCliHabVenInt.FromString(&GridStateFilterValue.Value) EndCase EndFor
/* Generated by DVelop Work With Plus Pattern [End] - Do not change */
EndSub
